t=int(input())
for i in range(t):
    n,k=map(int,input().split())
    if(k%5==0):
        tar=(k//5)
    else:
        tar=(k//5)+1 
    if(n%5==0):
        grp=(n//5)
    else:
        grp=(n//5)+1
    print(grp-tar)

